@using sv_68cc6cfe71154656859eece846ce0fbf.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row gap-4">
    @* ──── Left Sidebar (Filters) ──── *@
    <div style="min-width:250px;flex:0 0 25%;">
        <div class="card">
            <div class="card-header fw-semibold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading categories…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small mb-0">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="minPrice" />
                </div>
                <div class="mb-3">
                    <label class="form-label small mb-0">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="maxPrice" />
                </div>

                <hr />

                @* In Stock toggle *@
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <div class="d-grid gap-2">
                    <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
                </div>
            </div>
        </div>
    </div>

    @* ──── Main Content Area ──── *@
    <div style="flex:1 1 75%;min-width:0;">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary me-2" role="status"></div>
                <span>Loading products…</span>
            </div>
        }
        else if (searchResult is not null && searchResult.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found matching your criteria. Try adjusting your filters.
            </div>
        }
        else if (searchResult is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 text-nowrap">Sort by:</label>
                    <select class="form-select form-select-sm" style="width:auto;"
                            @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @(((searchResult.Page - 1) * searchResult.PageSize) + 1)–@(Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount))
                    of @searchResult.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
                @foreach (var product in searchResult.Items)
                {
                    <div class="col">
                        <div class="card h-100 shadow-sm product-card" role="button"
                             @onclick="() => OnProductSelected.InvokeAsync(product.Id)"
                             @onclick:stopPropagation>
                            @* Placeholder image *@
                            <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                 style="height:180px;" title="@product.Name">
                                <span class="text-muted">@product.Name</span>
                            </div>

                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-2">@RenderStars(product.Rating)</p>

                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2" style="width:fit-content;">Out of Stock</span>
                                }

                                <button class="btn btn-sm btn-success mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }" @onclick:stopPropagation>
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>

            @* Pagination *@
            @{ var totalPages = (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize); }
            @if (totalPages > 1)
            {
                <nav aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                    disabled="@(currentPage == 1)">Previous</button>
                        </li>

                        @for (int i = 1; i <= totalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }

                        <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                    disabled="@(currentPage == totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? searchResult;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = LoadProducts();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}
"}

